import React, { useRef, useCallback, useState, useEffect } from 'react';
import './styles.css'
import ProgressBar from './ProgressBar'

function ProgressBars() {
    const [bars, setBars] = useState([]);

    const queueRef = useRef([]);
    const processingRef = useRef(false);
    const resolversRef = useRef(new Map()); // 🔥 key fix

    async function processQueue() {
        if (processingRef.current) return;
        processingRef.current = true;

        while (queueRef.current.length > 0) {
            const id = queueRef.current.shift();

            await new Promise((resolve) => {
                // ✅ store resolver OUTSIDE React
                resolversRef.current.set(id, resolve);

                // activate immediately
                setBars((prev) =>
                    prev.map((b) =>
                        b.id === id ? { ...b, active: true } : b
                    )
                );
            });
        }

        processingRef.current = false;
    }

    function addBar() {
        const id = crypto.randomUUID();

        // 1. Add bar
        setBars((prev) => [...prev, { id, active: false }]);

        // 2. Queue it
        queueRef.current.push(id);

        // 3. Start processing immediately (NO WAIT)
        processQueue();
    }

    function handleComplete(id) {
        // resolve queue immediately
        const resolve = resolversRef.current.get(id);
        resolve?.();
        resolversRef.current.delete(id);

        setBars((prev) =>
            prev.map((b) =>
                b.id === id ? { ...b, active: false } : b
            )
        );
    }

    return (
        <>
            <div>
                {bars.map((bar, idx) => (
                    <ProgressBar key={bar.id}
                        active={bar.active}
                        duration={3000}
                        onComplete={() => handleComplete(bar.id)} />
                ))}
            </div>
            <button onClick={addBar}>+Add</button>
        </>
    )
}

export default ProgressBars
